Here's a modern MSTest test class covering async patterns, timeouts, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Async tests: just return Task — MSTest awaits them natively.
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("expected body", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected body", result);
    }

    // Timeout: use [Timeout] in ms. MSTest cancels the test if it exceeds this.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.IsNotNull(result);
    }

    // Cancellation: pass an already-cancelled token, expect TaskCanceledException.
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Error status code → HttpRequestException.
    [TestMethod]
    public async Task FetchAsync_ThrowsOnErrorStatus()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal stub to avoid real HTTP calls.
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _body;
        private readonly HttpStatusCode _statusCode;

        public MockHttpMessageHandler(string body, HttpStatusCode statusCode)
        {
            _body = body;
            _statusCode = statusCode;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_body)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Mechanism |
|---|---|
| **Async tests** | Return `Task` — MSTest awaits automatically, no `void` or `.Result` needed |
| **Timeouts** | `[Timeout(ms)]` attribute — MSTest fails the test if it exceeds the limit |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception assertions** | `Assert.ThrowsExceptionAsync<T>()` for async code paths |
| **No real HTTP** | Subclass `HttpMessageHandler` to stub `SendAsync` — avoids mocking frameworks |
